CREATE TABLE "Session" ("id" TEXT PRIMARY KEY,"clientId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "World" ("id" TEXT PRIMARY KEY,"title" TEXT NOT NULL,"description" TEXT NOT NULL,"version" TEXT NOT NULL,"published" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "WorldProgress" ("id" TEXT PRIMARY KEY,"sessionId" TEXT NOT NULL,"worldId" TEXT NOT NULL,"schemaVersion" INTEGER NOT NULL,"value" JSONB NOT NULL,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "WorldProgress_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "Session"("id") ON DELETE CASCADE,CONSTRAINT "WorldProgress_worldId_fkey" FOREIGN KEY ("worldId") REFERENCES "World"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "WorldProgress_sessionId_worldId_key" ON "WorldProgress"("sessionId","worldId");
CREATE TABLE "Score" ("id" TEXT PRIMARY KEY,"sessionId" TEXT NOT NULL,"worldId" TEXT NOT NULL,"category" TEXT NOT NULL,"value" DOUBLE PRECISION NOT NULL,"metadata" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "Score_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "Session"("id") ON DELETE CASCADE,CONSTRAINT "Score_worldId_fkey" FOREIGN KEY ("worldId") REFERENCES "World"("id") ON DELETE CASCADE);
CREATE INDEX "Score_worldId_category_value_idx" ON "Score"("worldId","category","value");
CREATE TABLE "ModelGuess" ("id" TEXT PRIMARY KEY,"sessionId" TEXT NOT NULL,"worldId" TEXT NOT NULL,"guess" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ModelGuess_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "Session"("id") ON DELETE CASCADE,CONSTRAINT "ModelGuess_worldId_fkey" FOREIGN KEY ("worldId") REFERENCES "World"("id") ON DELETE CASCADE);
CREATE TABLE "WorldRating" ("id" TEXT PRIMARY KEY,"sessionId" TEXT NOT NULL,"worldId" TEXT NOT NULL,"rating" INTEGER NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "WorldRating_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "Session"("id") ON DELETE CASCADE,CONSTRAINT "WorldRating_worldId_fkey" FOREIGN KEY ("worldId") REFERENCES "World"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "WorldRating_sessionId_worldId_key" ON "WorldRating"("sessionId","worldId");
CREATE TABLE "Provenance" ("id" TEXT PRIMARY KEY,"worldId" TEXT NOT NULL UNIQUE,"data" JSONB NOT NULL,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Provenance_worldId_fkey" FOREIGN KEY ("worldId") REFERENCES "World"("id") ON DELETE CASCADE);
CREATE TABLE "AnalyticsEvent" ("id" TEXT PRIMARY KEY,"sessionId" TEXT,"name" TEXT NOT NULL,"properties" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "AnalyticsEvent_name_createdAt_idx" ON "AnalyticsEvent"("name","createdAt");
